# NFR: Accuracy — LLM-judge evaluation harness (simplified)

import openai

EVAL_PROMPT = """
You are an impartial evaluator. Given a claim made by a claims chatbot and the source policy document,
determine whether the claim is factually supported.

Claim: {claim}
Source excerpt: {source}

Respond with JSON: {{"supported": true|false, "confidence": 0–1, "reason": "..."}}
"""

def evaluate_hallucination_rate(interactions: list[dict], source_docs: dict) -> float:
    """
    interactions: list of {query, response, cited_source_id}
    source_docs:  dict of {source_id: text}
    Returns fraction of claims judged unsupported.
    """
    client = openai.OpenAI()
    unsupported = 0

    for item in interactions:
        source_text = source_docs.get(item["cited_source_id"], "")
        result = client.chat.completions.create(
            model="gpt-4o-mini",
            response_format={"type": "json_object"},
            messages=[{
                "role": "user",
                "content": EVAL_PROMPT.format(
                    claim=item["response"],
                    source=source_text[:2000],
                ),
            }],
        )
        verdict = json.loads(result.choices[0].message.content)
        if not verdict["supported"]:
            unsupported += 1

    return unsupported / len(interactions)

