from dataclasses import dataclass, field
from typing import Optional
from enum import Enum

class NFRCategory(str, Enum):
    LATENCY       = "latency"
    ACCURACY      = "accuracy"
    SAFETY        = "safety"
    EXPLAINABILITY = "explainability"
    AVAILABILITY  = "availability"
    COST          = "cost"
    FAIRNESS      = "fairness"
    PRIVACY       = "privacy"

@dataclass
class NFRThreshold:
    category: NFRCategory
    metric: str
    target: str                        # e.g. "≤ 800 ms"
    measurement_method: str
    review_cadence: str
    owner: str
    regulatory_driver: Optional[str] = None

@dataclass
class GenAINFRSpec:
    feature_name: str
    version: str
    thresholds: list[NFRThreshold] = field(default_factory=list)

    def by_category(self, cat: NFRCategory) -> list[NFRThreshold]:
        return [t for t in self.thresholds if t.category == cat]

    def unowned(self) -> list[NFRThreshold]:
        return [t for t in self.thresholds if not t.owner]

    def regulatory_nfrs(self) -> list[NFRThreshold]:
        return [t for t in self.thresholds if t.regulatory_driver]

    def summary(self) -> str:
        cats = {t.category for t in self.thresholds}
        return (
            f"{self.feature_name} v{self.version}: "
            f"{len(self.thresholds)} NFRs across {len(cats)} categories"
        )
